// Payload: tenant_id, source (company|conversation_summary|secretary), content, metadata
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const tenantId = body.tenant_id;
const source = body.source || 'conversation_summary';
const content = (body.content || '').toString().trim();
const metadata = body.metadata || {};
if (!tenantId || !content) {
  throw new Error('tenant_id e content são obrigatórios');
}
return [{ json: { tenant_id: tenantId, source, content, metadata } }];

